mapper.select:
select qjrecord.*,employee.name as ename from `qjrecord` left join `employee` on qjrecord.userid = employee.id
and title like concat('%',#{title},'%') and userid =#{userid}
order by id desc

mapper.insert:
INSERT INTO qjrecord(
    userid, title, text, status, reason,
    starttime, endtime, time,ename
) VALUES (
             #{userid}, #{title}, #{text}, #{status}, #{reason},
             #{starttime}, #{endtime}, #{time},#{ename}
         )

mapper.update:
UPDATE qjrecord
title = #{title}, text = #{text}, status = #{status}, reason = #{reason}, start_time = #{startTime}, end_time = #{endTime}, time_slot = #{timeSlot}
WHERE id = #{id}
